mapper.select:
SELECT COUNT(*)
FROM trainer_booking
WHERE user_account_id = #{userAccountId}
  AND trainer_account_id = #{trainerAccountId}

mapper.delete:
DELETE FROM trainer_booking
WHERE user_account_id = #{userAccountId}
  AND trainer_account_id = #{trainerAccountId}

mapper.select:
SELECT NVL(content, '')
FROM trainer_booking
WHERE user_account_id = #{userAccountId}
  AND trainer_account_id = #{trainerAccountId}

mapper.update:
UPDATE trainer_booking
SET content = #{memo}
WHERE user_account_id = #{userAccountId}
  AND trainer_account_id = #{trainerAccountId}
